+  private getCursorOrder(orderBy: any): Array<{ field: string; dir: 'asc' | 'desc' }> {
+    if (!orderBy) {
+      return [];
+    }
+    const order: Array<{ field: string; dir: 'asc' | 'desc' }> = [];
+    for (const item of Array.isArray(orderBy) ? orderBy : [orderBy]) {
+      if (!item || typeof item !== 'object' || Array.isArray(item)) {
