+      }
+      for (const [field, direction] of Object.entries(item)) {
+        const dir = String(direction).toLowerCase();
+        if (dir !== 'asc' && dir !== 'desc') {
+          throw new BadRequestException('cursor pagination only supports asc and desc orderBy directions');
+        }
+        order.push({ field, dir });
